var e=JSON.parse(`[{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"나는 늘 중요한 순간에 눈을 돌렸다.","JPN":"私はいつも重要な瞬間に目を背けてきた。","ENG":"I always turned away from important moments.","TWN":"我總是在關鍵時刻把目光投向別處。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"어머니에게 죽을 뻔했을 때도.","JPN":"お母様に殺されそうになった時も。","ENG":"When Mother nearly killed me.","TWN":"差點被母親殺死的時候。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"아버지가 비참한 몰골이 되어 나타났을 때도.","JPN":"お父様が悲惨な姿で現れた時も。","ENG":"When Father appeared with such a terrible look.","TWN":"父親以悲慘的樣貌出現的時候。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"에델을 버리고 영지에서 도망쳤을 때도.","JPN":"エデルを捨てて、領地から逃げた時も。","ENG":"Even when I abandoned Edel and fled from the estate.","TWN":"丟下艾瑟兒，從領地中逃出去的時候。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EDEL_ESPR_NULL_QM","text":{"KOREA":"자, 이 책들을 주의 깊게 살펴 보세요.","JPN":"さあ、これらの本を注意深く読んでください。","ENG":"Now, take a careful look at these books.","TWN":"來，請記得要好好留意一下這些書。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EDEL_ESPR_NULL_QM","text":{"KOREA":"한 권씩 읽으면 흥미 위주로 쓰여진 것 같지만, 사실은 아니랍니다.","JPN":"一冊ずつ読むと興味本位で書かれた本のように見えますが、実は違います。","ENG":"If you read them one by one, they might seem to have been written just for the fun of it.","TWN":"如果你一本一本地讀下去，可能會覺得這些書是基於興趣寫出來的，但事實並非如此。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EDEL_ESPR_NULL_QM","text":{"KOREA":"행간과 행간, 단어와 단어 사이에 은밀하게 숨겨진 지식들을 하나로 엮어 가다 보면......","JPN":"行間と行間、単語と単語の間に秘められた知識を繋ぎ合わせていくと……","ENG":"But by reading between the lines and sewing the fragments of knowledge, hidden between words back together...","TWN":"只要把隱藏在句子和句子之間，單字和單字之間的知識串聯在一起……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EDEL_ESPR_NULL_QM","text":{"KOREA":"진실된 세계를 엿볼 수 있는 시야를 얻게 되죠.","JPN":"真実の世界を見ることができるようになります。","ENG":"You'll be able to gain an insight deep enough to peek through the world of truth.","TWN":"就可以獲得窺見真正世界的視野。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EDEL_ESPR_NULL_QM","text":{"KOREA":"지금은 이해하기 어렵겠지만, 언젠가 알게 되는 날이 올 거예요.","JPN":"今は理解できなくても、いつかわかる時が来るはずです。","ENG":"You're too young to understand now, but you'll definitely get there in the future.","TWN":"雖然現在你還很難理解，但妳總有一天會懂的。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……언니.","JPN":"……お姉さん。","ENG":"…Edel.","TWN":"……姊姊。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EDEL_ESPR_NULL_QM","text":{"KOREA":"이해가 잘 안 되시나요? 다시 한 번 가르쳐 드릴까요?","JPN":"理解できませんか？　もう一度教えてあげましょうか。","ENG":"Is it confusing? Do you want us to explain it again?","TWN":"不懂嗎？要再跟你講一遍嗎？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"사실은 나, 오늘 밤에 영지를 떠날 거예요.","JPN":"実は私、今夜領地を出ます。","ENG":"Actually, I am going to leave the estate tonight.","TWN":"其實，我今天晚上要離開領地了。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"EDEL_ESPR_NULL_QM","text":{"KOREA":"그래요……?","JPN":"そうですか……","ENG":"Is that so...?","TWN":"是嗎……？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EDEL_ESPR_NULL_QM","text":{"KOREA":"좋은 소식이네요. 영지 바깥에는 신기한 것도 흥미로운 것도 무척 많답니다.","JPN":"いい知らせですね。領地の外には不思議なものも、興味深いものもたくさんあります。","ENG":"That's good news! There are many odd and fascinating things to see outside of the estate.","TWN":"這是好消息啊。聽說領地外面有很多新奇、有趣的東西。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"EDEL_ESPR_NULL_QM","text":{"KOREA":"무서워하지 않아도 괜찮아요. 마음껏 많은 것을 경험하고 와 주세요.","JPN":"怖がらなくてもいいですよ。思いっきりたくさん経験してきてください。","ENG":"You don't have to be afraid. Please go out and enjoy yourself to the fullest.","TWN":"你不用害怕。盡情地去體驗更多東西，然後再回來吧。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"언니는 슬프지 않아요? 다시 오지 않을지도 몰라요.","JPN":"お姉さんは悲しくないのですか？　二度と戻ってこないかもしれません。","ENG":"Does it not make you sad? I might never return.","TWN":"姊姊不傷心嗎？我說不定就不再回來了。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"EDEL_ESPR_NULL_QM","text":{"KOREA":"……아뇨. 슬프지 않아요.","JPN":"……いいえ。悲しくありませんよ。","ENG":"...Of course not. We are not sad.","TWN":"……不，不傷心。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EDEL_ESPR_NULL_QM","text":{"KOREA":"레지나 님은 다시 돌아와 주실 테니까요. 책장 너머로 저희를 바라봐 주셨던 그 때처럼.","JPN":"レジーナ様はまたお戻りになるはずですから。本棚越しに我々を見てくださったあの時のように。","ENG":"We know you'll return, Miss Regina. Just like that time when you used to gaze at us from beyond the bookcase.","TWN":"蕾佳娜會回來的，就像從書架那頭看著我們那時候一樣。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_QM","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};